import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"上傳記錄檔","description":"如何上傳記錄檔以進行疑難排解。","frontmatter":{"title":"上傳記錄檔","description":"如何上傳記錄檔以進行疑難排解。","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.4/players/troubleshooting/uploading-logs.md","filePath":"versions/1.21.4/translated/zh_tw/players/troubleshooting/uploading-logs.md","lastUpdated":1760721669000}`);var a={name:`zh_tw/1.21.4/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">上傳記錄檔 <a class="header-anchor" href="#h1" aria-label="Permalink to “上傳記錄檔”">​</a></h1><p>在進行疑難排解時，通常需要提供記錄檔以幫助尋找問題的原因。</p><h2 id="why-should-i-upload-logs" tabindex="-1">為什麼我應該上傳記錄檔？ 為什麼我應該上傳記錄檔？ 為什麼我應該上傳記錄檔？ <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “為什麼我應該上傳記錄檔？ 為什麼我應該上傳記錄檔？ 為什麼我應該上傳記錄檔？”">​</a></h2><p>上傳記錄檔而不是只在論壇貼文中貼上記錄檔，讓其他人更快地解決你的問題。 它還允許你與他人分享你的記錄檔，而無需複製和貼上它們。</p><p>某些文字分享網站還會對記錄檔進行語法突顯，使其更易於閱讀，並且可能會對敏感資訊（例如你的使用者名稱或系統資訊）進行審查。</p><h2 id="崩潰報告" tabindex="-1">崩潰報告 <a class="header-anchor" href="#崩潰報告" aria-label="Permalink to “崩潰報告”">​</a></h2><p>當遊戲崩潰時，會自動產生崩潰報告。 它們只包含崩潰資訊，而不包含遊戲的實際記錄檔。 它們位於遊戲目錄中的 <code>crash-reports</code> 資料夾中。 它們只包含崩潰資訊，而不包含遊戲的實際記錄檔。 它們位於遊戲目錄中的 <code>crash-reports</code> 資料夾中。</p><p>有關崩潰報告的更多資訊，請參閱<a href="./crash-reports">崩潰報告</a>。</p><h2 id="locating-logs" tabindex="-1">尋找記錄檔 <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “尋找記錄檔”">​</a></h2><p>本指南涵蓋了官方 Minecraft 啟動器（通常稱為「原版啟動器」），對於第三方啟動器，你應該參閱其文件。</p><p>記錄檔位於遊戲目錄中的 logs 資料夾中，遊戲目錄可以在以下位置找到，具體取決於你的作業系統：</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>最新的記錄檔名為 <code>latest.log</code>，以及先前的記錄檔使用命名模式 <code>yyyy-mm-dd_number.log.gz</code>。</p><h2 id="uploading-logs" tabindex="-1">上傳記錄檔 <a class="header-anchor" href="#uploading-logs" aria-label="Permalink to “上傳記錄檔”">​</a></h2><p>記錄檔可以上傳到各種服務，例如：</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};